using System.Data;

namespace Firstronic.Areas.Manage.Controllers
{
  //===============================================================
  // CONTROLLER START : Areas
  //===============================================================

  [Authorize(Roles = "BF Administrator")]
  public class AreasController : BaseSecurityController
  {
    #region Fields
    private readonly DataContext db;
    #endregion Fields

    #region Ctor
    public AreasController()
    {
      db = new DataContext();
    }
    #endregion Ctor

    public ActionResult Index()
    {
      var model = db.Database.SqlQuery<tbl_PD_idt_areas_FULL>($@"SELECT        PD_idt_areas.AreaID, PD_idt_areas.Area, PD_idt_areas.ActiveReport, PD_idt_areas.PlexOperation, PD_idt_areas.FlowID, PD_idt_areas.Active_Inventory, PD_idt_areas.Facility_Key, 
                         Common_Facilities.Facility_Name, PD_idt_areas.Area_Type_ID, PD_idt_areas.Able_To_Lock
FROM            PD_idt_areas INNER JOIN
                         Common_Facilities ON PD_idt_areas.Facility_Key = Common_Facilities.Facility_Key Order by FlowID asc").ToArray().ToList().AsQueryable();

      return View(model);
    }


    // GET:
    public ActionResult Create()
    {
      var model = new tbl_PD_idt_areas_FULL();
      var FirstronicFacilitiesList = new List<SelectListItem>();
      FirstronicFacilitiesList = Framework.Functions.Dropdowns.GetFirstronicFacilitiesList(null);
      model.FacilityList = FirstronicFacilitiesList;
      var ActiveReport_List = new List<SelectListItem>();
      ActiveReport_List = Framework.Functions.Dropdowns.GetBooleanList(null);
      model.ActiveReport_List = ActiveReport_List;
      var PlexOperation_List = new List<SelectListItem>();
      PlexOperation_List = Framework.Functions.Dropdowns.GetBooleanList(null);
      model.PlexOperation_List = PlexOperation_List;
      var Active_Inventory_List = new List<SelectListItem>();
      Active_Inventory_List = Framework.Functions.Dropdowns.GetBooleanList(null);
      model.Active_Inventory_List = Active_Inventory_List;
      var Able_To_Lock_List = new List<SelectListItem>();
      Able_To_Lock_List = Framework.Functions.Dropdowns.GetBooleanList(null);
      model.Able_To_Lock_List = Able_To_Lock_List;

      var Area_Type_List = new List<SelectListItem>();
      Area_Type_List = Framework.Functions.Dropdowns.GetAreasTypeList(null);
      model.Area_Type_List = Area_Type_List;

      var VerifyPlex_List = new List<SelectListItem>();
      VerifyPlex_List = Framework.Functions.Dropdowns.GetBooleanList(null);
      model.VerifyPlex_List = VerifyPlex_List;
      var RecordPlex_List = new List<SelectListItem>();
      RecordPlex_List = Framework.Functions.Dropdowns.GetBooleanList(null);
      model.RecordPlex_List = RecordPlex_List;
      var SetUpPlex_List = new List<SelectListItem>();
      SetUpPlex_List = Framework.Functions.Dropdowns.GetBooleanList(null);
