    public ActionResult FillStations(int? AreaID, string All = "", int onlyactive = 1)
    {
      // All: Means SHOW ALL Option

      SqlParameter[] sqlParameters = new SqlParameter[]{
          new SqlParameter("@AreaID",SqlDbType.Int){Value = AreaID},
          new SqlParameter("@onlyactive",SqlDbType.Int){Value = onlyactive}
      };

      if (AreaID == 0)
      {
        All = "ALL";
      }

      var stations = Firstronic.Framework.Queries.GetSelectedFromQuery(@"SELECT [StationID], StationName as StationName  FROM [PD_idt_stations] Where (@AreaID = 0 OR AreaID=@AreaID)  AND (@onlyactive = -1 OR BeFirstActive=@onlyactive)", sqlParameters);

      if (All == "ALL")
      {
        stations = Firstronic.Framework.Queries.GetSelectedFromQuery(@"SELECT 0 as StationID, 'ALL' as StationName UNION ALL SELECT [StationID]
                  , StationName as StationName  FROM [PD_idt_stations] Where (@AreaID = 0 OR AreaID=@AreaID)  AND (@onlyactive = -1 OR BeFirstActive=@onlyactive)", sqlParameters);
      }

      return Json(stations, JsonRequestBehavior.AllowGet);
    }

