        PrintLabelPlex_List = PrintLabelPlex_List
      };

      model.RecordPlex = Firstronic.Framework.Queries.GetBooleanFromQuery($@"SELECT  case when COUNT(*) >0 then cast(1 as bit) else cast(0 as bit) end  FROM PD_tbl_Areas_RecordPlex WHERE areaid=@Id", parameters);

      return View(model);
    }

    // POST EDIT
    [HttpPost]
    [ValidateAntiForgeryToken]
    [MultipleButtonAction(Name = "action", Argument = "Edit")]
    public ActionResult Edit(tbl_PD_idt_areas_FULL model)
    {
      if (ModelState.IsValid)
      {
        var id = model.AreaID;

        SqlParameter[] parameters = new SqlParameter[]{
          new SqlParameter("@Id",SqlDbType.Int){Value = model.AreaID},
        };

        var record = Framework.Functions.Utilies.ConvertTo<tbl_PD_idt_areas>(Firstronic.Framework.Queries.GetDatatableFromQuery("SELECT *   FROM PD_idt_areas WHERE AreaID=@Id ", parameters)).FirstOrDefault();


        if (record is null)
        {
          this.NotifyError("Record not found.");
          return RedirectToAction("Index");
        }


        SqlParameter[] updateParameters = new SqlParameter[]{
          new SqlParameter("@AreaID",SqlDbType.Int){Value = model.AreaID},
          new SqlParameter("@Area",SqlDbType.VarChar){Value =(model.Area ?? "").ToString()},
          new SqlParameter("@ActiveReport",SqlDbType.Bit){Value =model.ActiveReport},
          new SqlParameter("@PlexOperation",SqlDbType.Bit){Value =model.PlexOperation},
          new SqlParameter("@FlowID",SqlDbType.Int){Value =model.FlowID},
          new SqlParameter("@Active_Inventory",SqlDbType.Bit){Value =model.Active_Inventory},
          new SqlParameter("@Able_To_Lock",SqlDbType.Bit){Value =model.Able_To_Lock},
          new SqlParameter("@Area_Type_ID",SqlDbType.Int){Value =model.Area_Type_ID},
          new SqlParameter("@Facility_Key",SqlDbType.Int){Value =model.Facility_Key}
        };

        var result = Firstronic.Framework.Queries.ExecuteQuery("UPDATE PD_idt_areas SET " +
          "Area = @Area," +
          "ActiveReport = @ActiveReport," +
          "PlexOperation = @PlexOperation," +
          "FlowID = @FlowID," +
          "Active_Inventory = @Active_Inventory," +
          "Able_To_Lock = @Able_To_Lock," +
          "Area_Type_ID = @Area_Type_ID," +
          "Facility_Key = @Facility_Key  WHERE AreaID = @AreaID", updateParameters);


        if (result > 0)
        {

          var res1 = Firstronic.Framework.Queries.ExecuteQuery($@"DELETE FROM PD_tbl_Areas_RecordPlex WHERE AreaID = @Id", parameters);

          if (model.RecordPlex == true)
          {
            var res4_insert = Firstronic.Framework.Queries.ExecuteQuery($@"INSERT INTO PD_tbl_Areas_RecordPlex VALUES (@Id)", parameters);
          }

          this.NotifySuccess("Successfully saved.");
        }
        else if (result == 0)
          this.NotifySuccess("Record can not save!");
        else
          this.NotifyError("Error in database.");

        return RedirectToAction("Edit", new { id = record.AreaID });
      }

      return View(model);
    }

