          </div>
          <div class="input-group mb-3">

            @Html.LabelFor(y => y.PlexOperation, new { @class = "m-0 fs-14" })
            @Html.DropDownListFor(y => y.PlexOperation, (IEnumerable<SelectListItem>)Model.PlexOperation_List, new { @class = "md-input" })
          </div>
          <div class="input-group mb-3">

            @Html.LabelFor(y => y.ActiveReport, new { @class = "m-0 fs-14" })
            @Html.DropDownListFor(y => y.ActiveReport, (IEnumerable<SelectListItem>)Model.ActiveReport_List, new { @class = "md-input" })
          </div>
          <div class="input-group mb-3">

            @Html.LabelFor(y => y.Active_Inventory, new { @class = "m-0 fs-14" })
            @Html.DropDownListFor(y => y.Active_Inventory, (IEnumerable<SelectListItem>)Model.Active_Inventory_List, new { @class = "md-input" })
          </div>
          <div class="input-group mb-3">

            @Html.LabelFor(y => y.Able_To_Lock, new { @class = "m-0 fs-14" })
            @Html.DropDownListFor(y => y.Able_To_Lock, (IEnumerable<SelectListItem>)Model.Able_To_Lock_List, new { @class = "md-input" })
          </div>
          <div class="input-group mb-3">
            @Html.LabelFor(y => y.Area_Type_ID, new { @class = "m-0 fs-14" })
            @Html.DropDownListFor(y => y.Area_Type_ID, (IEnumerable<SelectListItem>)Model.Area_Type_List, new { @class = "md-input" })

          @* @Html.LabelFor(y => y.Area_Type_ID, new { @class = "m-0 fs-14" })*@
          @*  @Html.TextBoxFor(y => y.Area_Type_ID, new { @class = "md-input" })*@
          </div>
          <div class="input-group mb-3">

            @Html.LabelFor(y => y.Visible, new { @class = "m-0 fs-14" })
            @Html.DropDownListFor(y => y.Visible, (IEnumerable<SelectListItem>)Model.Visible_List, new { @class = "md-input" })
          </div>
        </li>
        <li aria-hidden="true">
          <div class="input-group mb-3">

            @Html.LabelFor(y => y.RecordPlex, new { @class = "m-0 fs-14" })
            @Html.DropDownListFor(y => y.RecordPlex, (IEnumerable<SelectListItem>)Model.RecordPlex_List, new { @class = "form-control" })
          </div>
        </li>
      </ul>

      <div class="tab-pane">
        <div class="form-group">
          <div class="form-group mt-4 pt-4 border-top">
