```csharp
//===============================================================
// AREAS - DataTable Version (for views that iterate over areas)
//===============================================================
public static DataTable GetAreasDataTable(string Filter = "")
{
  using (DataContext db = new DataContext())
  {
    // Add IsVisible filter intelligently
    string finalFilter = "";
    if (string.IsNullOrWhiteSpace(Filter))
    {
      // No existing filter - add WHERE clause
      finalFilter = "WHERE IsVisible = 1 ";
    }
    else if (Filter.ToUpper().Contains("WHERE"))
    {
      // Existing filter with WHERE - add AND condition
      finalFilter = Filter.TrimEnd() + " AND IsVisible = 1 ";
    }
    else
    {
      // Existing filter without WHERE - add WHERE clause before it
      finalFilter = "WHERE IsVisible = 1 AND " + Filter;
    }

    DataTable dt = Firstronic.Framework.Queries.GetDatatableFromQuery(
      "SELECT [AreaID], [Area], [Area_Type_ID], [ActiveReport], [PlexOperation], [FlowID], [Active_Inventory], [Facility_Key], [Able_To_Lock] " +
      "FROM PD_idt_areas " + finalFilter + "ORDER BY FlowID ASC");

    return dt;
  }
}
```

Then replace queries like this:

