    //===============================================================
    public static List<SelectListItem> GetPartNumbersList(int? SelectedItem, string Filter = "", bool includeNa = false, bool onlyManufacturingSource = true)
    {

      var options = new List<SelectListItem>();

      using (DataContext db = new DataContext())
      {
        db.Configuration.UseDatabaseNullSemantics = true;

        IList<tbl_CS_idt_partnumbers> publisherList = new List<tbl_CS_idt_partnumbers>();

        tbl_CS_idt_partnumbers[] query;

        if (onlyManufacturingSource == true)
        {
          query = db.Database.SqlQuery<tbl_CS_idt_partnumbers>($@"SELECT [PartID],[PartNumber] FROM PART P
LEFT JOIN PART_SOURCE PS
ON P.Part_Source_Key = PS.Part_Source_Key
WHERE P.IsActive=1 
AND Ps.Manufactured_Part = 1 
Order By Partnumber asc").ToArray();
        }
        else
        {
          query = db.Database.SqlQuery<tbl_CS_idt_partnumbers>($@"SELECT [PartID],[PartNumber] FROM PART P
LEFT JOIN PART_SOURCE PS
ON P.Part_Source_Key = PS.Part_Source_Key
WHERE P.IsActive=1 
Order By Partnumber asc").ToArray();
        }

        var rows = query.ToList();

        foreach (var rowData in rows)
        {

          var o = new SelectListItem
          {
            Value = rowData.PartID.ToString(),
            Text = rowData.PartNumber.ToString(),
            Selected = rowData.PartID == SelectedItem ? true : false
          };
          options.Add(o);
        }
      }

      if (includeNa == true)
      {
        var o = new SelectListItem
        {
          Value = "0",
          Text = "NA",
          Selected = true
        };
        options.Insert(0, o);
      }

      return options;
    }

