      conditions.Add(customSubquery);
    }

    string whereClause = "WHERE " + string.Join(" AND ", conditions);

    string query = "SELECT [AreaID], [Area], [Area_Type_ID], [ActiveReport], [PlexOperation], [FlowID], [Active_Inventory], [Facility_Key], [Able_To_Lock], [IsVisible] " +
                   "FROM PD_idt_areas " + whereClause + " ORDER BY FlowID ASC";

    DataTable dt = Firstronic.Framework.Queries.GetDatatableFromQuery(query, parameters.ToArray());

    return dt;
  }
