    //===============================================================
    // AREAS - DataTable Version (for views that iterate over areas)
    // Parameters prevent SQL injection and provide type safety
    //===============================================================
    public static DataTable GetAreasDataTable(
      int[] areaTypeIds = null,
      bool? activeReport = null,
      bool? plexOperation = null,
      bool? activeInventory = null,
      int? facilityKey = null,
      int[] includeAreaIds = null,
      int[] excludeAreaIds = null,
      string customSubquery = null)
    {
      using (DataContext db = new DataContext())
      {
        var parameters = new List<SqlParameter>();
        var conditions = new List<string>();

        // Always filter by IsVisible
        conditions.Add("IsVisible = 1");

        // Area Type IDs
        if (areaTypeIds != null && areaTypeIds.Length > 0)
        {
          if (areaTypeIds.Length == 1)
          {
            conditions.Add("Area_Type_ID = @AreaTypeId");
            parameters.Add(new SqlParameter("@AreaTypeId", SqlDbType.Int) { Value = areaTypeIds[0] });
          }
          else
          {
            var inClause = string.Join(",", areaTypeIds.Select((id, index) => $"@AreaTypeId{index}"));
            conditions.Add($"Area_Type_ID IN ({inClause})");
            for (int i = 0; i < areaTypeIds.Length; i++)
            {
              parameters.Add(new SqlParameter($"@AreaTypeId{i}", SqlDbType.Int) { Value = areaTypeIds[i] });
            }
          }
        }

        // Active Report
        if (activeReport.HasValue)
        {
          conditions.Add("ActiveReport = @ActiveReport");
          parameters.Add(new SqlParameter("@ActiveReport", SqlDbType.Bit) { Value = activeReport.Value });
        }

        // Plex Operation
        if (plexOperation.HasValue)
        {
          conditions.Add("PlexOperation = @PlexOperation");
          parameters.Add(new SqlParameter("@PlexOperation", SqlDbType.Bit) { Value = plexOperation.Value });
        }

        // Active Inventory
        if (activeInventory.HasValue)
        {
          conditions.Add("Active_Inventory = @ActiveInventory");
          parameters.Add(new SqlParameter("@ActiveInventory", SqlDbType.Bit) { Value = activeInventory.Value });
        }

        // Facility Key
        if (facilityKey.HasValue)
        {
          conditions.Add("Facility_Key = @FacilityKey");
          parameters.Add(new SqlParameter("@FacilityKey", SqlDbType.Int) { Value = facilityKey.Value });
        }

        // Include specific Area IDs
        if (includeAreaIds != null && includeAreaIds.Length > 0)
        {
          if (includeAreaIds.Length == 1)
          {
            conditions.Add("AreaID = @IncludeAreaId");
            parameters.Add(new SqlParameter("@IncludeAreaId", SqlDbType.Int) { Value = includeAreaIds[0] });
          }
          else
          {
            var inClause = string.Join(",", includeAreaIds.Select((id, index) => $"@IncludeAreaId{index}"));
            conditions.Add($"AreaID IN ({inClause})");
            for (int i = 0; i < includeAreaIds.Length; i++)
            {
              parameters.Add(new SqlParameter($"@IncludeAreaId{i}", SqlDbType.Int) { Value = includeAreaIds[i] });
            }
          }
        }

        // Exclude specific Area IDs
        if (excludeAreaIds != null && excludeAreaIds.Length > 0)
        {
          if (excludeAreaIds.Length == 1)
          {
            conditions.Add("AreaID <> @ExcludeAreaId");
            parameters.Add(new SqlParameter("@ExcludeAreaId", SqlDbType.Int) { Value = excludeAreaIds[0] });
          }
          else
          {
            var notInClause = string.Join(",", excludeAreaIds.Select((id, index) => $"@ExcludeAreaId{index}"));
            conditions.Add($"AreaID NOT IN ({notInClause})");
            for (int i = 0; i < excludeAreaIds.Length; i++)
            {
              parameters.Add(new SqlParameter($"@ExcludeAreaId{i}", SqlDbType.Int) { Value = excludeAreaIds[i] });
            }
          }
        }

        // Custom subquery (e.g., "AreaID in (select AreaID from PD_idt_stations)")
        // Note: This should only be used for trusted subqueries, not user input
        if (!string.IsNullOrWhiteSpace(customSubquery))
        {
          conditions.Add(customSubquery);
        }

        string whereClause = "WHERE " + string.Join(" AND ", conditions);

        string query = "SELECT [AreaID], [Area], [Area_Type_ID], [ActiveReport], [PlexOperation], [FlowID], [Active_Inventory], [Facility_Key], [Able_To_Lock], [IsVisible] " +
                       "FROM PD_idt_areas " + whereClause + " ORDER BY FlowID ASC";

        DataTable dt = Firstronic.Framework.Queries.GetDatatableFromQuery(query, parameters.ToArray());

        return dt;
      }
    }

