            @{
              DataTable dt_downtime = new DataTable();

              DataTable dt_areas = Firstronic.Framework.Functions.Queries.GetDatatableFromQuery(@"SELECT [AreaID],[Area],[Area_Type_ID] FROM [PD_idt_areas] where (Area_Type_ID = 1) and ActiveReport = 1 order by FlowID asc");

