              dt_downtime.Columns.Add("Area");

              DateTime diainicial = dia_current;

              for (int ii = 0; ii < 7; ii++)
              {
                dt_downtime.Columns.Add(diainicial.AddDays(-ii).ToString("yyyy-MM-dd"));
              }

              foreach (DataRow area in dt_areas.Rows)
              {

                DataRow nrow = dt_downtime.NewRow();

                nrow[0] = area["Area"].ToString();

                for (int ii = 0; ii < 7; ii++)
                {
                  SqlParameter[] dwParameters = new SqlParameter[]{
                    new SqlParameter("@DiaIniAdd30",SqlDbType.DateTime){Value = diainicial.AddDays(-ii).AddHours(+6).AddHours(+24).ToString("MM/dd/yyyy HH:mm:ss")},
                    new SqlParameter("@DiaIniAdd6",SqlDbType.DateTime){Value = diainicial.AddDays(-ii).AddHours(+6).ToString("MM/dd/yyyy HH:mm:ss")},
                    new SqlParameter("@AreaID",SqlDbType.Int){Value = area[0]},
                    new SqlParameter("@DiaInicialAdd6",SqlDbType.DateTime){Value = diainicial.AddDays(-ii).AddHours(+6).ToString("yyyy-MM-dd")}
                  };

                  int dw = Firstronic.Framework.Queries.GetIntFromQuery(@"SELECT SUM(DATEDIFF(MINUTE,TrnDate,isnull(IssueSolveDate,CASE WHEN GETDATE()<@DiaIniAdd30 THEN GETDATE() ELSE @DiaIniAdd30 END))) as Minutes FROM PD_tbl_station_issues INNER JOIN PD_idt_issuestype ON PD_tbl_station_issues.IssueTypeID = PD_idt_issuestype.IssueTypeID INNER JOIN PD_idt_stations ON PD_tbl_station_issues.StationID = PD_idt_stations.StationID INNER JOIN PD_idt_areas ON PD_idt_stations.AreaID = PD_idt_areas.AreaID WHERE(PD_tbl_station_issues.TrnDate BETWEEN @DiaIniAdd6 and @DiaIniAdd30) AND PD_idt_areas.AreaID=@AreaID", dwParameters);

                  //Check for goaldaily data....

                  int dailygoasl = Firstronic.Framework.Queries.GetIntFromQuery(@"SELECT isnull(SUM(Hours),0) as Minutes FROM [Part_Operation_Packout_Goal_Daily_Details] where AreaID=@AreaID and TrnDate=@DiaInicialAdd6", dwParameters);

                  if (dailygoasl > dw)
                  {
                    nrow[ii + 1] = dailygoasl;
                  }
                  else
                  {
                    nrow[ii + 1] = dw;
                  }
                }

                dt_downtime.Rows.Add(nrow);

              }

              <div class="mvc-grid mvc-grid-excel-mode fs-13">
                <table border="1">
                  <thead>
                    <tr>
                      @foreach (System.Data.DataColumn col in dt_downtime.Columns)
                      {
                        <th>@col.Caption</th>
                      }
                    </tr>
                  </thead>
                  <tbody>
                    @{
                      var areaidx = 0;
                    }
                    @foreach (System.Data.DataRow rowsu in dt_downtime.Rows)
                    {
                      var areaid = dt_areas.Rows[areaidx][0];

                      var typeidx = -1;

                      var previousvalue = 0;
                      <tr>
                        @foreach (var cell in rowsu.ItemArray)
                        {
                          if (typeidx >= 0)
                          {
                            int newv = int.Parse(cell.ToString());

                            previousvalue = 0;

                            try
                            {
                              previousvalue = int.Parse(rowsu[typeidx + 2].ToString());
                            }
                            catch (Exception)
                            {

                            }

                            if (newv > previousvalue)
                            {
                              <td><a href="@Url.Action("Area","Downtime",new {year=diainicial.AddDays(typeidx).Year,month=diainicial.AddDays(-typeidx).Month,day=diainicial.AddDays(-typeidx).Day, id=areaid })" class="uk-text-danger"><span class="material-icons uk-text-danger"> arrow_drop_up </span> @cell.ToString()</a></td>
                            }
                            else
                            {
                              <td><a href="@Url.Action("Area","Downtime",new {year=diainicial.AddDays(typeidx).Year,month=diainicial.AddDays(-typeidx).Month,day=diainicial.AddDays(-typeidx).Day, id=areaid })" class="uk-text-success"><span class="material-icons uk-text-success"> arrow_drop_down </span> @cell.ToString()</a></td>
                            }

                            previousvalue = newv;

                          }
                          else
                          {
                            <td><a href="@Url.Action("Index","Areas",new {year=Model.year,month=Model.month,day=Model.day, id=areaid })">@cell.ToString()</a></td>
                          }
                          typeidx++;
                        }
                      </tr>

                      areaidx++;
                    }
                  </tbody>
                </table>
              </div>
            }
          </div>
        </div>
      </div>
    </div>
  </div>
</div>

