            vespertino = Firstronic.Framework.Queries.GetIntFromQuery(@"SELECT SUM(CASE WHEN [PD_tbl_units_tracking].JobSide='B' THEN BPlacements WHEN [PD_tbl_units_tracking].JobSide='A' THEN APlacements END) as [Total] FROM [PD_tbl_units_tracking] WITH(NOLOCK,index(idx_Placements)) INNER JOIN CS_idt_partnumbers WITH(NOLOCK) ON[PD_tbl_units_tracking].PartID = CS_idt_partnumbers.PartID WHERE TrnDate between @DiaCurrentAdd18 and @DiaCurrentAdd30 and IsRework = 0 and AreaID = 1 and StationID = @StationID", VespertinoParameters);
          }
          catch
          {

          }

          var matutino = 0;

          try
          {
            SqlParameter[] MatutinoParameters = new SqlParameter[]
            {
              new SqlParameter("@DiaCurrentAdd6", SqlDbType.DateTime){Value = dia_current.AddHours(+6).ToString("MM/dd/yyyy HH:mm:ss")},
              new SqlParameter("@DiaCurrentAdd18", SqlDbType.DateTime){Value = dia_current.AddHours(+6).AddHours(+12).ToString("MM/dd/yyyy HH:mm:ss")},
              new SqlParameter("@StationID", SqlDbType.Int){Value = station[1].ToString()}
            };

            matutino = Firstronic.Framework.Queries.GetIntFromQuery(@"SELECT SUM(CASE WHEN [PD_tbl_units_tracking].JobSide='B' THEN BPlacements WHEN [PD_tbl_units_tracking].JobSide='A' THEN APlacements END) as [Total] FROM [PD_tbl_units_tracking] WITH(NOLOCK,index(idx_Placements)) INNER JOIN CS_idt_partnumbers WITH(NOLOCK) ON[PD_tbl_units_tracking].PartID = CS_idt_partnumbers.PartID WHERE TrnDate between @DiaCurrentAdd6 and @DiaCurrentAdd18 and IsRework = 0 and AreaID = 1 and StationID = @StationID", MatutinoParameters);
          }
          catch
          {

          }

          dt_Summary.Rows.Add(station[0].ToString(), matutino.ToString("N0"), vespertino.ToString("N0"), (matutino + vespertino).ToString("N0"));

          totalm += matutino;

          totalv += vespertino;

        }

        dt_Summary.Rows.Add("Total", totalm.ToString("N0"), totalv.ToString("N0"), (totalv + totalm).ToString("N0"));

        Double NPIS = -99;
      }

