<div class="md-card">
  <div class="md-card-content mvc-grid">
    <table class="table">
      <tr>
        <th>Area</th>
        <th>Description</th>
        @for (int ii = 0; ii < 7; ii++)
        {
          <th>@dia_current.AddDays(-ii).ToString("yyyy-MM-dd")</th>
        }
      </tr>
      @{
        DataTable dtValuesTotal = new DataTable();
        for (int ii = 0; ii < 7; ii++)
        {
          dtValuesTotal.Columns.Add("col_" + ii, typeof(double));
        }

        dtValuesTotal.Rows.Add(0, 0, 0, 0, 0, 0, 0); //Total
        dtValuesTotal.Rows.Add(0, 0, 0, 0, 0, 0, 0); //Availab
        dtValuesTotal.Rows.Add(0, 0, 0, 0, 0, 0, 0); //Efficecy
        dtValuesTotal.Rows.Add(0, 0, 0, 0, 0, 0, 0); //Quality
      }
      @foreach (DataRow row in dt_areas2.Rows)
      {
        DataTable dtValues = new DataTable();
        for (int ii = 0; ii < 7; ii++)
        {
          dtValues.Columns.Add("col_" + ii, typeof(double));
        }

        dtValues.Rows.Add(0, 0, 0, 0, 0, 0, 0); //Total
        dtValues.Rows.Add(0, 0, 0, 0, 0, 0, 0); //Availab
        dtValues.Rows.Add(0, 0, 0, 0, 0, 0, 0); //Efficecy
        dtValues.Rows.Add(0, 0, 0, 0, 0, 0, 0); //Quality
        dtValues.Rows.Add(0, 0, 0, 0, 0, 0, 0); //OEE MINUTES
        dtValues.Rows.Add(0, 0, 0, 0, 0, 0, 0); //AVA MINUTES

        SqlParameter[] dtWorkcentersparameters = new SqlParameter[]{
          new SqlParameter("@AreaID",SqlDbType.Int){Value = row[0].ToString()},
        };

        DataTable dt_workcenters = Firstronic.Framework.Queries.GetDatatableFromQuery(@"SELECT PD_idt_stations.StationID, PD_idt_stations.StationName FROM PD_idt_stations WHERE (PD_idt_stations.AreaID = @AreaID) AND (PD_idt_stations.BeFirstActive = 1) Order by PD_idt_stations.StationName ASC", dtWorkcentersparameters);

        if (dt_workcenters.Rows.Count > 0)
        {
          for (int ii = 0; ii < 7; ii++)
