      <h3 class="heading_a uk-margin-bottom">Down Time Reason</h3>
      <div id="bar-chart"></div>
    </div>

    <script type="text/javascript" nonce="@Html.ScriptNonce()">
        function updatehistory() {

        var data_area = JSON.stringify({
             'year': @Model.year,
            'month': @Model.month,
            'day': @Model.day,
            'id': '@Model.areaid'
          });

        var colors_array = ['#bc3c3c', '#79bc3c'];

          //GET DATA FOR BAR
          $.ajax({
            type: "POST",
            data: data_area,
            url: "/Dashboards/Areas/DWArea",
            contentType: "application/json; charset=utf-8",
            success: function (chData) {
              var aData = $.parseJSON(chData);
              if (aData.length > 0) {
                var morrisDonut = Morris.Bar({
                  element: 'bar-chart',
                  data: aData,
                  xkey: 'label',
                  ykeys: ['value'],
                  labels: ['Minutes: ']
                });
              }
            },
            async: false
          });
        };

        $(document).ready(function () {
          updatehistory()
        })
    </script>
  </div>

</div>


