<div class="md-card">
  <div class="md-card-content">
    <h3 class="heading_a uk-margin-bottom">Daily Goal Issues</h3>
    <div class="mvc-grid mvc-grid-excel-mode">
      @{
        SqlParameter[] dtTicketsparameters = new SqlParameter[]{
                      new SqlParameter("@AreaID",SqlDbType.Int){Value =Model.areaid},
                      new SqlParameter("@DiaCurrent",SqlDbType.DateTime){Value =dia_current.ToString("MM/dd/yyyy")},
        };

        DataTable dt_tickets = Firstronic.Framework.Queries.GetDatatableFromQuery(@"SELECT Part_Operation_Packout_Goal_Daily_Details.WrtDate,
CS_idt_partnumbers.PartNumber, PD_idt_issuestype.IssueType, Part_Operation_Packout_Goal_Daily_Details.ShiftVM, Part_Operation_Packout_Goal_Daily_Details.Hours AS Minutos, Part_Operation_Packout_Goal_Daily_Details.SupervisorComments FROM Part_Operation_Packout_Goal_Daily_Details INNER JOIN CS_idt_partnumbers ON Part_Operation_Packout_Goal_Daily_Details.PartID = CS_idt_partnumbers.PartID INNER JOIN PD_idt_issuestype ON Part_Operation_Packout_Goal_Daily_Details.IssueTypeID = PD_idt_issuestype.IssueTypeID
WHERE (Part_Operation_Packout_Goal_Daily_Details.AreaID = @AreaID) AND (Part_Operation_Packout_Goal_Daily_Details.TrnDate = @DiaCurrent) Order by WrtDate", dtTicketsparameters);
      }

      <table border="1">
        <thead>
          <tr>
            @foreach (System.Data.DataColumn col in dt_tickets.Columns)
            {
              <th>@col.Caption</th>
            }
          </tr>
        </thead>
        <tbody>
          @foreach (System.Data.DataRow rowsu in dt_tickets.Rows)
          {
            <tr>
              @foreach (var cell in rowsu.ItemArray)
              {
                <td>@cell.ToString()</td>
              }
            </tr>
          }
        </tbody>
      </table>
    </div>
  </div>
</div>




<script type="text/javascript" nonce="@Html.ScriptNonce()">
  document.getElementById("btnExport").addEventListener('click', function () {
    /* Create worksheet from HTML DOM TABLE */
    var wb = XLSX.utils.table_to_book(document.getElementById("ExportYieldDetails"));
    /* Export to file (start a download) */
    const d = new Date();
    let text = moment(d).format('YYYYMMDDHHMMSS');



    XLSX.writeFile(wb, "Downtime" + text + ".xlsx");
  });
</script>

