@using System.Data;
@using System.Data.SqlClient;
@model Firstronic.Areas.Dashboards.Models.customreport_area

@{
  /**/

  DateTime dia_current = new DateTime(Model.year, Model.month, Model.day);
  DateTime dia_yesterday = dia_current.AddDays(-1);
  DateTime dia_tomorrow = dia_current.AddDays(+1);

  var u_yesterday = new RouteValueDictionary(Url.RequestContext.RouteData.Values);
  u_yesterday.Add("year", dia_yesterday.Year);
  u_yesterday.Add("month", dia_yesterday.Month);
  u_yesterday.Add("day", dia_yesterday.Day);
  u_yesterday.Add("Building_Key", Model.Building_Key.ToString());

  var u_tomorrow = new RouteValueDictionary(Url.RequestContext.RouteData.Values);
  u_tomorrow.Add("year", dia_tomorrow.Year);
  u_tomorrow.Add("month", dia_tomorrow.Month);
  u_tomorrow.Add("day", dia_tomorrow.Day);
  u_tomorrow.Add("Building_Key", Model.Building_Key.ToString());

  Model.current = dia_current;


  SqlParameter[] parameters = new SqlParameter[]{
    new SqlParameter("@AreaID",SqlDbType.Int) {Value =Model.areaid},
  };

  var AreaName = Firstronic.Framework.Queries.GetStringFromQuery("SELECT [Area] FROM [PD_idt_areas] WHERE AreaID=@AreaID", parameters);

  DataTable dt_areas = Firstronic.Framework.Functions.Queries.GetDatatableFromQuery("SELECT [AreaID],[Area] FROM [PD_idt_areas] WHere (Area_Type_ID = 1 or Area_Type_ID = 2) and ActiveReport=1 order by flowid asc");

  string nextareaid = Model.areaid.ToString();
  string nextarea = AreaName;

  string prevareaid = Model.areaid.ToString();
  string prevarea = AreaName;

  int index = -1;
  DataRow[] rows = dt_areas.Select("AreaID='" + Model.areaid + "'");
  if (rows.Count() > 0)
  {
    index = dt_areas.Rows.IndexOf(rows[0]);
  }

  try
  {
    nextareaid = dt_areas.Rows[index + 1][0].ToString();
    nextarea = dt_areas.Rows[index + 1][1].ToString();
  }
  catch
  {
    nextareaid = dt_areas.Rows[0][0].ToString();
    nextarea = dt_areas.Rows[0][1].ToString();
  }

  try
  {
    prevareaid = dt_areas.Rows[index - 1][0].ToString();
    prevarea = dt_areas.Rows[index - 1][1].ToString();
  }
  catch
  {
    prevareaid = dt_areas.Rows[dt_areas.Rows.Count - 1][0].ToString();
    prevarea = dt_areas.Rows[dt_areas.Rows.Count - 1][1].ToString();
  }

}

