<div class="uk-card">
  <div class="uk-grid" uk-grid>
    <script type="text/javascript" nonce="@Html.ScriptNonce()">
      let totaloee = 0;
      let totalsta = 0;

      let totalavailability = 0;
      let totalefficency = 0;
      let totalquantity = 0;

      let totalMinutesProgrammed = 0;
      let totalMinutesOEE = 0;

    </script>
