            @foreach (Firstronic.Framework.APIs.Station.OEE stationOEE in Model.StationsOEE)
            {
              bool displayStation = true;

              if (Model.areaid == 6)
              {
                if (stationOEE.total == 0)
                {
                  displayStation = false;
                }
              }

              if (stationOEE.stationName == null)
              {
                Console.WriteLine("as");
              }

              if (1 == 1 && stationOEE.stationName != null) //if (displayStation)
              {
                <div class="uk-width-1-6@l uk-width-1-2@s">
                  <div class="dashboard-widget dashboard-widget-top-blue">
                    <div class="dashboard-widget-title">
                      <a class="login-text" href="~/Dashboards/Station/Index/@stationOEE.stationID.ToString()?year=@Model.year&month=@Model.month&day=@Model.day">
