                          </a>
                          (<span id="txtProgW_@stationOEE.stationID.ToString()"></span>/<span id="txtProgA_@stationOEE.stationID.ToString()"></span>)
                        </div>
                        <div>
                          <a class="editdetailstv" href="~/Dashboards/TVs/Station_Efficency/@stationOEE.stationID.ToString()?year=@Model.year&month=@Model.month&day=@Model.day&all=1">
                            Efficency: <span id="txtEfi_@stationOEE.stationID.ToString()"></span>%
                          </a>
                          (<span id="txtEfiT_@stationOEE.stationID.ToString()"></span>/<span id="txtEfiH_@stationOEE.stationID.ToString()"></span>)
                        </div>
                        <div>
                          <a class="editdetailstv" href="~/Dashboards/TVs/Station_Efficency/@stationOEE.stationID.ToString()?year=@Model.year&month=@Model.month&day=@Model.day&all=1">
                            Quality: <span id="txtCal_@stationOEE.stationID.ToString()"></span>%
                          </a>
                          (<span id="txtQuaT_@stationOEE.stationID.ToString()"></span>/<span id="txtQuaH_@stationOEE.stationID.ToString()"></span>)
                        </div>
                        <div>
                          <a class="editdetailstv" href="~/Dashboards/TVs/Station_Efficency/@stationOEE.stationID.ToString()?year=@Model.year&month=@Model.month&day=@Model.day&all=1">
                            Retest: <span id="txtEfiRetest_@stationOEE.stationID.ToString()"></span>%
                          </a>
                          (<span id="txtEfiRetestT_@stationOEE.stationID.ToString()"></span>/<span id="txtEfiRetestH_@stationOEE.stationID.ToString()"></span>)
                        </div>
                        <div class="">
                        </div>
                      </div>
                    </div>
                  </div>
                </div>

                <script type="text/javascript" nonce="@Html.ScriptNonce()">
                  function updatehistory_@stationOEE.stationID.ToString()_f() {

                  var data_st = JSON.stringify({
                       'year': @Model.year,
                      'month': @Model.month,
                      'day': @Model.day,
                      'StationID': '@stationOEE.stationID.ToString()'
                    });

                    //GET VALUES.
                  var disponibilidad = @stationOEE.availability;
                  var eficiencia = @stationOEE.efficency;
                  var eficiencia_retest = @stationOEE.efficency_Retest;
                  var calidad = @stationOEE.quality;

                  var minutesworked = @stationOEE.minutesWorked;
                  var minutesworked_retest = @stationOEE.minutesWorked_Retest;
                  var eficienciaH = @stationOEE.minutesAvailables;

                  var minutesprogrammed = @stationOEE.minutesProgrammed;
                  var minutesavailables = @stationOEE.minutesAvailables;
                  var minutesOEE = @stationOEE.minutesOEE;

                  var floatOEE = @stationOEE.total;

                  $("#txtDis_@stationOEE.stationID.ToString()").html((disponibilidad * 100).toFixed(2));
                  $("#txtEfi_@stationOEE.stationID.ToString()").html((eficiencia * 100).toFixed(2));
                  $("#txtEfiRetest_@stationOEE.stationID.ToString()").html((eficiencia_retest * 100).toFixed(2));
                  $("#txtCal_@stationOEE.stationID.ToString()").html((calidad * 100).toFixed(2));

                  $("#txtProgW_@stationOEE.stationID.ToString()").html(minutesavailables.toFixed(0));     // MINUTES AVAILABLES
                  $("#txtProgA_@stationOEE.stationID.ToString()").html(minutesprogrammed.toFixed(0)); // MINUTES PROGRAMMED

                  $("#txtEfiT_@stationOEE.stationID.ToString()").html(minutesworked.toFixed(0)); // MINUTES WORKED
                  $("#txtEfiH_@stationOEE.stationID.ToString()").html(eficienciaH.toFixed(0)); // MINUES AVAILABLES...


                  $("#txtEfiRetestT_@stationOEE.stationID.ToString()").html(minutesworked_retest.toFixed(0)); // MINUTES WORKED
                  $("#txtEfiRetestH_@stationOEE.stationID.ToString()").html(eficienciaH.toFixed(0)); // MINUES AVAILABLES...

                  $("#txtQuaT_@stationOEE.stationID.ToString()").html(minutesOEE.toFixed(0));
                  $("#txtQuaH_@stationOEE.stationID.ToString()").html(minutesworked.toFixed(0));

                    // CALCULATE OEE
                  var good = Math.floor(((parseFloat(disponibilidad) * parseFloat(eficiencia) * parseFloat(calidad)))*100);
                  var bad = 100 - good;


                  if ( floatOEE > 0) {
                    totalMinutesProgrammed = totalMinutesProgrammed + minutesprogrammed;
                    totalMinutesOEE = totalMinutesOEE + minutesOEE;

                    totalavailability = totalavailability + parseFloat(disponibilidad);
                    totalefficency = totalefficency + parseFloat(eficiencia);
                    totalquantity = totalquantity + parseFloat(calidad);

                    totaloee = totaloee + good;
                    totalsta = totalsta + 1;
                  }

                  var data_fg = JSON.stringify({
                    'good': good,
                    'bad': bad
                  });

                  var colors_array = ['#bc3c3c', '#79bc3c'];

                  if (good == 0) {
                    colors_array[0] = "#888";
                    colors_array[1] = "#888";
                  }

                    //GET DATA FOR BAR
                    $.ajax({
                      type: "POST",
                      data: data_fg,
                      url: "/Dashboards/Manufacturing/CurrentOEE",
                      contentType: "application/json; charset=utf-8",
                      success: function (chData) {
                        var aData = $.parseJSON(chData);
                        var morrisDonut = Morris.Donut({
                          element: 'bar-fg_@stationOEE.stationID.ToString()',
                          data: aData,
                          formatter: function (x) { return x + "%" },
                          colors: colors_array,
                          resize: true,
                          redraw: true
                        });
                        morrisDonut.select(1);
                      },
                      async: false
                    });
                  };

                  $(document).ready(function () {
                    updatehistory_@stationOEE.stationID.ToString()_f();
                  })
                </script>


              }
            }



            <script type="text/javascript" nonce="@Html.ScriptNonce()">


              function updateaverage() {

                var nostations = totalsta;


                var average = totalMinutesOEE / totalMinutesProgrammed;

                $("#txt_Summary").html(parseFloat(average * 100).toFixed(2) + "%");
                $("#txt_SummaryOEE").html(totalMinutesOEE.toFixed(0));
                $("#txt_SummaryTotal").html(totalMinutesProgrammed.toFixed(0));

              };

              $(document).ready(function () {
                updateaverage()
              })

            </script>


          </div>
        </div>
      </div>

      <div class="md-card">
        <div class="md-card-toolbar">
          <h3 class="md-card-toolbar-heading-text"> <a href="@Url.Action("Area","DownTime", new { Area="Dashboards", id = Model.areaid,year=Model.year,month=Model.month,day=Model.day })">Down Time Reason</a> </h3>
        </div>
