        <script type="text/javascript" nonce="@Html.ScriptNonce()">
        function updatehistory() {

        var data_area = JSON.stringify({
             'year': @Model.year,
            'month': @Model.month,
            'day': @Model.day,
            'id': '@Model.areaid'
          });

