            type: "POST",
            data: data_area,
            url: "/Dashboards/Areas/DWArea",
            contentType: "application/json; charset=utf-8",
            success: function (chData) {
              var aData = $.parseJSON(chData);
              if (aData.length > 0) {
                var morrisDonut = Morris.Bar({
                  element: 'bar-chart',
