        };

        $(document).ready(function () {
          updatehistory()
        })
        </script>

      </div>
    </div>

    <div class="uk-width-1-2@m">
      <div class="md-card">
        <div class="md-card-toolbar">
          <h3 class="md-card-toolbar-heading-text"> Tickets </h3>
        </div>
        <div class="md-card-content">
          <div class="mvc-grid mvc-grid-excel-mode">
            @{
              DateTime dialimit = dia_tomorrow;

              if (DateTime.Now < dia_tomorrow)
              {
                dialimit = DateTime.Now;
              }
              else
              {
                dialimit = dialimit.AddHours(6);
              }

              DataTable fullTickets = new DataTable();

              foreach (Firstronic.Framework.APIs.Station.OEE stationOEE in Model.StationsOEE)
              {
                SqlParameter[] stationParameters = new SqlParameter[]{
                  new SqlParameter("@StationID",SqlDbType.Int) {Value = stationOEE.stationID},
                  new SqlParameter("@DiaCurrent",SqlDbType.DateTime){Value = dia_current.Date.AddHours(6)},
                  new SqlParameter("@DiaLimit",SqlDbType.DateTime){Value = dialimit},
                  new SqlParameter("@DiaTomorrow",SqlDbType.DateTime){Value = dia_tomorrow.Date.AddHours(6)},
                };

                DataTable dt_tickets_yesterday = Firstronic.Framework.Queries.GetDatatableFromQuery(@"SELECT PD_tbl_station_issues.AutoID, PD_tbl_station_issues.StationID, cast(@DiaCurrent as datetime) as TrnDate, PD_tbl_station_issues.ControlID, PD_tbl_station_issues.IssueTypeID, PD_tbl_station_issues.IssueID, PD_tbl_station_issues.IssueComments, PD_tbl_station_issues.IssueSolve, PD_tbl_station_issues.IssueSolution, PD_tbl_station_issues.SolveBy, PD_tbl_station_issues.CategoryLevel, PD_tbl_station_issues.PartID, PD_tbl_station_issues.Side, PD_tbl_station_issues.Facility_Key, isnull(IssueSolveDate,@DiaLimit) as IssueSolveDate, PD_idt_areas.Area, PD_idt_issuestype.IssueType, PD_tbl_issue_ids.IssueDescription, CS_idt_partnumbers.PartNumber,PD_idt_stations.StationName, DATEDIFF(MINUTE,cast(@DiaCurrent as datetime),isnull(IssueSolveDate,@DiaLimit)) as Minutes FROM PD_tbl_station_issues LEFT JOIN PD_idt_stations ON PD_tbl_station_issues.StationID = PD_idt_stations.StationID LEFT JOIN   PD_idt_areas ON PD_idt_stations.AreaID = PD_idt_areas.AreaID LEFT JOIN  PD_idt_issuestype ON PD_tbl_station_issues.IssueTypeID = PD_idt_issuestype.IssueTypeID LEFT JOIN   PD_tbl_issue_ids ON PD_tbl_station_issues.IssueID = PD_tbl_issue_ids.IssueID LEFT JOIN CS_idt_partnumbers ON PD_tbl_station_issues.PartID = CS_idt_partnumbers.PartID  WHERE TrnDate< @DiaCurrent AND IssueSolveDate>@DiaCurrent AND (PD_idt_stations.stationid = @StationID OR PD_idt_stations.stationid in (SELECT Sub_Station_ID  FROM [Part_Station_SubStation] WHERE Station_ID= @StationID) ) Order by TrnDate desc", stationParameters);

                DataTable dt_tickets = Firstronic.Framework.Queries.GetDatatableFromQuery(@"SELECT PD_tbl_station_issues.AutoID, PD_tbl_station_issues.StationID, PD_tbl_station_issues.TrnDate, PD_tbl_station_issues.ControlID, PD_tbl_station_issues.IssueTypeID, PD_tbl_station_issues.IssueID, PD_tbl_station_issues.IssueComments, PD_tbl_station_issues.IssueSolve, PD_tbl_station_issues.IssueSolution, PD_tbl_station_issues.SolveBy, PD_tbl_station_issues.CategoryLevel, PD_tbl_station_issues.PartID, PD_tbl_station_issues.Side, PD_tbl_station_issues.Facility_Key, isnull(IssueSolveDate,@DiaLimit) as IssueSolveDate, PD_idt_areas.Area, PD_idt_issuestype.IssueType, PD_tbl_issue_ids.IssueDescription, CS_idt_partnumbers.PartNumber,PD_idt_stations.StationName, DATEDIFF(MINUTE,TrnDate,isnull(IssueSolveDate,@DiaLimit)) as Minutes FROM PD_tbl_station_issues LEFT JOIN PD_idt_stations ON PD_tbl_station_issues.StationID = PD_idt_stations.StationID LEFT JOIN   PD_idt_areas ON PD_idt_stations.AreaID = PD_idt_areas.AreaID LEFT JOIN  PD_idt_issuestype ON PD_tbl_station_issues.IssueTypeID = PD_idt_issuestype.IssueTypeID LEFT JOIN   PD_tbl_issue_ids ON PD_tbl_station_issues.IssueID = PD_tbl_issue_ids.IssueID LEFT JOIN CS_idt_partnumbers ON PD_tbl_station_issues.PartID = CS_idt_partnumbers.PartID  WHERE TrnDate between @DiaCurrent and @DiaTomorrow AND (PD_idt_stations.stationid = @StationID OR PD_idt_stations.stationid in (SELECT Sub_Station_ID  FROM [Part_Station_SubStation] WHERE Station_ID= @StationID) ) Order by TrnDate desc", stationParameters);

                DataTable dt_tickets_tomorrow = Firstronic.Framework.Queries.GetDatatableFromQuery(@"SELECT TOP 1 PD_tbl_station_issues.AutoID, PD_tbl_station_issues.StationID, PD_tbl_station_issues.TrnDate, PD_tbl_station_issues.ControlID, PD_tbl_station_issues.IssueTypeID, PD_tbl_station_issues.IssueID, PD_tbl_station_issues.IssueComments, PD_tbl_station_issues.IssueSolve, PD_tbl_station_issues.IssueSolution, PD_tbl_station_issues.SolveBy, PD_tbl_station_issues.CategoryLevel, PD_tbl_station_issues.PartID, PD_tbl_station_issues.Side, PD_tbl_station_issues.Facility_Key, cast(@DiaLimit as datetime) as IssueSolveDate, PD_idt_areas.Area, PD_idt_issuestype.IssueType, PD_tbl_issue_ids.IssueDescription, CS_idt_partnumbers.PartNumber,PD_idt_stations.StationName, DATEDIFF(MINUTE,TrnDate,cast(@DiaLimit as datetime)) as Minutes FROM PD_tbl_station_issues LEFT JOIN PD_idt_stations ON PD_tbl_station_issues.StationID = PD_idt_stations.StationID LEFT JOIN   PD_idt_areas ON PD_idt_stations.AreaID = PD_idt_areas.AreaID LEFT JOIN  PD_idt_issuestype ON PD_tbl_station_issues.IssueTypeID = PD_idt_issuestype.IssueTypeID LEFT JOIN   PD_tbl_issue_ids ON PD_tbl_station_issues.IssueID = PD_tbl_issue_ids.IssueID LEFT JOIN CS_idt_partnumbers ON PD_tbl_station_issues.PartID = CS_idt_partnumbers.PartID  WHERE TrnDate < @DiaTomorrow AND isnull(IssueSolveDate,getdate())>@DiaTomorrow AND (PD_idt_stations.stationid = @StationID OR PD_idt_stations.stationid in (SELECT Sub_Station_ID  FROM [Part_Station_SubStation] WHERE Station_ID= @StationID) ) Order by TrnDate desc", stationParameters);

                dt_tickets.Merge(dt_tickets_tomorrow);
                dt_tickets_yesterday.Merge(dt_tickets);

                fullTickets.Merge(dt_tickets_yesterday);
              }

              //fullTickets.DefaultView.Sort = "TrnDate";
              //fullTickets = fullTickets.DefaultView.ToTable();
            }

            <table>
              <tr>
                <th>TrnDate</th>
                <th>Station</th>
                <th>Type</th>
                <th>Description</th>
                <th>Comments</th>
                <th>Solved</th>
                <th>Edit</th>
              </tr>

              @foreach (DataRow row in fullTickets.Rows)
              {
                <tr>
                  <td>@row["TrnDate"].ToString()</td>
                  <td>@row["StationName"].ToString()</td>
                  <td>@row["IssueType"].ToString()</td>
                  <td>@row["IssueDescription"].ToString()</td>
                  <td>@row["IssueComments"].ToString()</td>
                  <td>@row["IssueSolve"].ToString()</td>
                  <td class="bc-gray" width="70px"><a class="editdetails" href="@Url.Action("Details", "Portal", new { Area="Tickets",id = row["AutoID"].ToString() })">Edit</a></td>
                </tr>
              }

            </table>
          </div>
          <script type="text/javascript" nonce="@Html.ScriptNonce()">

            $(document).on('click', 'a.editdetails', function (e) {
              var w = 1200;
              var h = 900;
              var left = window.screen.availLeft + (screen.width / 2) - (w / 2);
              var top = window.screen.availTop + (screen.height / 2) - (h / 2);
              var url = $(this).attr('href');
              window.open(url, "Details", 'toolbar=no, location=no, directories=no, status=no, menubar=no, scrollbars=yes, resizable=no, copyhistory=no, width=' + w + ', height=' + h + ', top=' + top + ', left=' + left);
              return false;
            });
          </script>
          <script type="text/javascript" nonce="@Html.ScriptNonce()">

            $(document).on('click', 'a.editdetailstv', function (e) {
              var w = 1400;
              var h = 900;
              var left = window.screen.availLeft + (screen.width / 2) - (w / 2);
              var top = window.screen.availTop + (screen.height / 2) - (h / 2);
              var url = $(this).attr('href');
              window.open(url, "Details", 'toolbar=no, location=no, directories=no, status=no, menubar=no, scrollbars=1, resizable=no, copyhistory=no, width=' + w + ', height=' + h + ', top=' + top + ', left=' + left);
              return false;
            });
          </script>
        </div>
      </div>
    </div>
  </div>
</div>

