                       'year': @Model.year,
                      'month': @Model.month,
                      'day': @Model.day,
                      'StationID': '@stationOEE.stationID.ToString()'
                    });

                    //GET VALUES.
                  var disponibilidad = @stationOEE.availability;
                  var eficiencia = @stationOEE.efficency;
                  var eficiencia_retest = @stationOEE.efficency_Retest;
                  var calidad = @stationOEE.quality;

