                          colors: colors_array,
                          resize: true,
                          redraw: true
                        });
                        morrisDonut.select(1);
                      },
                      async: false
                    });
                  };

                  $(document).ready(function () {
                    updatehistory_@stationOEE.stationID.ToString()_f();
                  })
                </script>


              }
