@{
  SqlParameter[] areaParameters = new SqlParameter[]{
    new SqlParameter("@AreaID",SqlDbType.Int) {Value = Model.areaid},
  };


  DateTime currentMonth = new DateTime(dia_current.Year, dia_current.Month, 1, 6, 0, 0);
  DateTime currentMonthEnd = currentMonth.AddMonths(+1);


  DataTable dt_workcentersoee = Firstronic.Framework.Queries.GetDatatableFromQuery(@"SELECT    PD_idt_stations.StationID, PD_idt_stations.StationName, PD_idt_stations.AreaID, PD_idt_stations.IsActive, PD_idt_stations.DownTimeCodeID, PD_idt_stations.LastPieceTime, PD_idt_stations.LastPartID, PD_idt_stations.LastJob, PD_idt_stations.LastJobText, PD_idt_stations.LastJobType, PD_idt_stations.LastJobQty, PD_idt_stations.LastJobQtyBuild, PD_idt_stations.LastHourQty, PD_idt_stations.LastRate, PD_idt_stations.LastSide, PD_idt_stations.BeFirstActive, PD_idt_stations.LockStatus, PD_idt_stations.LastFormat, PD_idt_stations.DashVisible, PD_idt_stations.ProdVisible, PD_idt_stations.LockMachines, PD_idt_stations.Alias, PD_idt_stations.LastBinID, PD_idt_stations.PLC_Name, PD_idt_stations.Workcenter_Key, PD_idt_stations.Workcenter_Key_Kanban, PD_idt_stations.Workcenter_PLC_Name, PD_idt_stations.Workcenter_PLC_Name_Kanban, PD_idt_stations.AutoID, PD_idt_stations.Facility_Key, PD_idt_stations.Allow_Plex_Transactions, PD_idt_stations.Workcenter_Key_1, PD_idt_stations.Workcenter_Key_2, PD_idt_stations.Workcenter_Key_Kanban_1, PD_idt_stations.Workcenter_Key_Kanban_2, PD_idt_stations.Workcenter_PLC_Name_1, PD_idt_stations.Workcenter_PLC_Name_2, PD_idt_stations.Workcenter_PLC_Name_Kanban_1, PD_idt_stations.Workcenter_PLC_Name_Kanban_2, PD_idt_stations.Allow_LoadMaterial, PD_idt_stations.Custom_Labels, PD_idt_stations.Allow_Plex_Transactions_2, CS_idt_partnumbers.PartNumber, EN_idt_downtimes_codes.RazonSpecific,datediff(MINUTE,LastPieceTime,GETDATE()) as Downtime  FROM            PD_idt_stations LEFT JOIN  CS_idt_partnumbers ON PD_idt_stations.LastPartID = CS_idt_partnumbers.PartID LEFT JOIN EN_idt_downtimes_codes ON PD_idt_stations.DownTimeCodeID = EN_idt_downtimes_codes.DownTimeCodeID WHERE (PD_idt_stations.AreaID = @AreaID) AND (PD_idt_stations.DashVisible = 1) Order by PD_idt_stations.SortNo ASC", areaParameters);

  DataTable dtFull = new DataTable();

  foreach (DataRow row_station in dt_workcentersoee.Rows)
  {
    string StationID = row_station["StationID"].ToString();
    string StationName = row_station["StationName"].ToString();

    SqlParameter[] stationParameters = new SqlParameter[] {
      new SqlParameter("@StationID", SqlDbType.Int) { Value = Convert.ToInt32(StationID) },
      new SqlParameter("@AreaID", SqlDbType.Int) { Value = Model.areaid },
      new SqlParameter("@StationName", SqlDbType.NVarChar) { Value = StationName },
      new SqlParameter("@CurrentMonth",SqlDbType.DateTime){Value = currentMonth},
      new SqlParameter("@CurrentMonthEnd",SqlDbType.DateTime){Value = currentMonthEnd}
    };

    DataTable dtChangeOvers = Firstronic.Framework.Queries.GetDatatableFromQuery(@"SELECT Changovers.*,CASE WHEN IssueDescription IS NULL THEN '' ELSE IssueDescription END as Ticket,StationName,CS_idt_partnumbers.PartNumber,Part_Station_Setup.Side FROM (
SELECT SetupID,LAG(Max(trndate),1,0) OVER (ORDER BY min(trndate) ASC) as EndTime,min(trndate) as JobStart,Max(trndate) as JobEnd, DATEDIFF(MINUTE,LAG(Max(trndate),1,0) OVER (ORDER BY min(trndate) ASC),min(trndate)) as Minutes,dbo.fnGetShift(min(trndate)) as Shift,StationID FROM [PD_tbl_units_tracking] WITH(NOLOCK) where StationID=@StationID and TrnDate between @CurrentMonth and @CurrentMonthEnd and SSNIndex=1 and IsRework=0 GROUP BY SetupID,StationID ) Changovers
LEFT JOIN  (SELECT PD_tbl_station_issues.StationID, PD_tbl_station_issues.TrnDate, PD_tbl_station_issues.IssueComments, PD_tbl_station_issues.IssueDetail, PD_idt_issuestype.ReduceProgramation, PD_idt_issuestype.ReduceRate, PD_idt_stations.AreaID, PD_tbl_issue_ids.IssueDescription, PD_idt_issuestype.IssueType
FROM            PD_tbl_station_issues INNER JOIN
                 PD_tbl_issue_ids ON PD_tbl_station_issues.IssueID = PD_tbl_issue_ids.IssueID INNER JOIN
                 PD_idt_issuestype ON PD_tbl_station_issues.IssueTypeID = PD_idt_issuestype.IssueTypeID INNER JOIN
                 PD_idt_stations ON PD_tbl_station_issues.StationID = PD_idt_stations.StationID
WHERE        (PD_idt_issuestype.ReduceProgramation = 1) AND (PD_idt_stations.AreaID = @AreaID) AND (PD_tbl_station_issues.TrnDate BETWEEN @CurrentMonth and @CurrentMonthEnd)
) Tickets
ON Changovers.StationID=Tickets.StationID AND Tickets.TrnDate between Changovers.EndTime AND Changovers.JobStart LEFT JOIN PD_idt_stations ON Changovers.StationID = PD_idt_stations.StationID LEFT JOIN Part_Station_Setup ON Part_Station_Setup.Setup_ID =Changovers.SetupID LEFT JOIN CS_idt_partnumbers ON CS_idt_partnumbers.PartID=Part_Station_Setup.PartID Order by JobStart ", stationParameters);

    if (dtChangeOvers.Rows.Count > 0)
    {
      dtChangeOvers.Rows.Remove(dtChangeOvers.Rows[0]);
      dtChangeOvers.AcceptChanges();
    }

    if (dtChangeOvers.Rows.Count > 0)
    {
      dtFull.Merge(dtChangeOvers);
      dtFull.AcceptChanges();
    }


  }


  dtFull.Columns.Add("Quantity", typeof(int));
  dtFull.Columns.Add("Minimo", typeof(int));
  dtFull.Columns.Add("Maximo", typeof(int));


}
<div class="md-card">
  <div class="md-card-content">
    <div class="uk-grid uk-margin-remove fc-white pd-b-15" uk-grid>
      <div class="uk-width-1-3@m uk-width-1-1@s text-left pd-5">
        @Html.TextBoxFor(y => y.current, new { @id = "ddlDateUpdate", @Value = Model.current.ToString("MM/dd/yyyy"), style = "width: 80%;text-align: center;font-size: 14px;" })
      </div>
