    @Html.HiddenFor(y => y.areaid, new { id = "txtAreaID" })

    @if (dtFull.Rows.Count > 0)
    {
      DataTable dtTotals = dtFull.AsEnumerable()
        .Where(row => row.Field<int>("Minutes") > 0 && row.Field<string>("Ticket") == "")
        .GroupBy(row => new { Shift = row["Shift"] })
        .Select(g =>
        {
          var nrow = dtFull.NewRow();

          nrow["Minutes"] = g.Average(row => row.Field<int>
          ("Minutes"));
          nrow["Minimo"] = g.Min(row => row.Field<int>
            ("Minutes"));
          nrow["Maximo"] = g.Max(row => row.Field<int>
          ("Minutes"));
          nrow["Shift"] = g.First().Field<string>
          ("Shift");
          nrow["Quantity"] = g.Count();

          return nrow;
        })
        .CopyToDataTable();


      <table border="1" class="w-100 fc-white table-border-color">
        <thead>
          <tr>
            <th class="text-center fs-18"> Shift </th>
            <th class="text-center fs-18"> Goal </th>
            <th class="text-center fs-18"> Average </th>
            <th class="text-center fs-18"> Minimo </th>
            <th class="text-center fs-18"> Maximo </th>
            <th class="text-center fs-18"> < 20 min </th>
            <th class="text-center fs-18"> < 40 min </th>
            <th class="text-center fs-18"> < 60 min </th>
            <th class="text-center fs-18"> > 60 min </th>
            <th class="text-center fs-18"> ChangeOvers </th>
          </tr>
        </thead>
        <tbody>
          @for (int shift = 1; shift < 5; shift++)
          {





            double count0 = 0;
            double count20 = 0;
            double count40 = 0;
            double count60 = 0;



            DataRow[] rows0 = dtFull.Select("Shift='" + shift + "' AND Minutes>=0 and Minutes<20 AND Ticket=''");
            count0 = (double)rows0.Length;

            DataRow[] rows20 = dtFull.Select("Shift='" + shift + "' AND Minutes>=20 and Minutes<40 AND Ticket=''");
            count20 = (double)rows20.Length;

            DataRow[] rows40 = dtFull.Select("Shift='" + shift + "' AND Minutes>=40 and Minutes<60 AND Ticket=''");
            count40 = (double)rows40.Length;

            DataRow[] rows60 = dtFull.Select("Shift='" + shift + "' AND Minutes>=60 AND Ticket=''");
            count60 = (double)rows60.Length;

            DataRow[] rowShift = dtTotals.Select("Shift='" + shift + "'");

            if (rowShift.Length > 0)
            {
              double efficency = count0 / (count0 + count20 + count40 + count60);

              string yellowClass = "";

              if (double.Parse(rowShift[0]["Minutes"].ToString()) > 20)
              {
                yellowClass = "fc-yellow";
              }
              else
              {
                yellowClass = "fc-green";
              }

              <tr>
                <td class="fs-60">@rowShift[0]["Shift"].ToString()</td>
