                <td class="fs-60 @yellowClass">@rowShift[0]["Minutes"].ToString()</td>
                <td class="fs-60">@rowShift[0]["Minimo"].ToString()</td>
                <td class="fs-60">@rowShift[0]["Maximo"].ToString()</td>
                <td class="fs-60">@count0 <span class="fs-16">[@((count0 / (count0 + count20 + count40 + count60)).ToString("P0").Replace(" ",""))]</span></td>
                <td class="fs-60">@count20 <span class="fs-16">[@((count20 / (count0 + count20 + count40 + count60)).ToString("P0").Replace(" ", ""))]</span></td>
                <td class="fs-60">@count40 <span class="fs-16">[@((count40 / (count0 + count20 + count40 + count60)).ToString("P0").Replace(" ", ""))]</span></td>
                <td class="fs-60">@count60 <span class="fs-16">[@((count60 / (count0 + count20 + count40 + count60)).ToString("P0").Replace(" ", ""))]</span></td>
                <td class="fs-60">@rowShift[0]["Quantity"].ToString()</td>
              </tr>
            }
          }
        </tbody>
      </table>

      if (Request.IsAuthenticated)
      {
        <div class="pd-t-20 text-right">
          <input id="btnExport" type="button" value="Export" class="md-btn md-btn-primary md-btn-small" />
        </div>
      }

      <div class="hide">
        <table border="1" class="hide" id="ExportYieldDetails">
